    //ed_hataiStDt.setMandatory(false); 
    //ed_hataiEndDt.setMandatory(false); 
    ed_vltPlc.setMandatory(false);

    //납부 초기화
    ica_pmntSlipDt.setMandatory(false);
    ica_pmntDt.setMandatory(false);
